const weight = $input.first().json.body.weight;
const height = $input.first().json.body.height / 100; // convert cm to meters
const bmi = (weight / (height * height)).toFixed(2);

let category = '';
if (bmi < 18.5) {
  category = 'Underweight';
} else if (bmi >= 18.5 && bmi < 25) {
  category = 'Normal Weight';
} else if (bmi >= 25 && bmi < 30) {
  category = 'Overweight';
} else {
  category = 'Obese';
}

return [{
  json: {
    ...($input.first().json.body),
    bmi: parseFloat(bmi),
    bmiCategory: category
  }
}];

